// Naccache-Whelan bar-width attack — enumerates candidate strings whose total advance width
// matches a redaction bar, exploiting the fact that bar width encodes character-sequence width.

import type { FontMetrics } from '../font/metrics.js';

/** A candidate string generated by the Naccache-Whelan enumeration. */
export interface Candidate {
	/** The candidate text. */
	text: string;
	/** Absolute difference in PDF units between the candidate's rendered width and the target bar. */
	widthError: number;
	/** Relative likelihood score 0–1 based on width match and character frequency. */
	probability: number;
}

export interface NaccacheWhelanOptions {
	/** Width of the redaction bar in PDF user-space units. */
	barWidth: number;
	/** Font metrics used to compute advance widths. */
	metrics: FontMetrics;
	/** Active font size in PDF units. */
	fontSize: number;
	/** Fraction of barWidth accepted as tolerance. Default: 0.03 (3%). */
	tolerance?: number;
	/** Maximum candidates to return. Default: 50. */
	maxCandidates?: number;
	/** Surrounding text before the redaction for plausibility filtering. */
	contextBefore?: string;
	/** Surrounding text after the redaction for plausibility filtering. */
	contextAfter?: string;
}

