/** English letter bigram frequency table for scoring (higher = more common). */
const BIGRAM_SCORES: Readonly<Record<string, number>> = {
	th: 10, he: 9, in: 9, er: 8, an: 8, re: 8, on: 7, en: 7, at: 7, es: 7,
	st: 7, to: 7, nt: 6, or: 6, nd: 6, is: 6, ar: 6, al: 6, it: 6, as: 6,
};

/** Compute a character frequency score for a candidate string (0–1). */
function scoreByFrequency(text: string): number {
	if (text.length < 2) return 0.3;
	let score = 0;
	const lower = text.toLowerCase();
	for (let i = 0; i < lower.length - 1; i++) {
		const bigram = lower.slice(i, i + 2);
		score += BIGRAM_SCORES[bigram] ?? 0;
	}
	// Normalise — max possible ~10 per bigram * (len-1) bigrams
	return Math.min(1, score / (10 * (lower.length - 1)));
}

/**
 * Enumerate candidate strings whose rendered width at `fontSize` matches `barWidth`
 * within the given tolerance.
 *
 * Uses the Naccache-Whelan observation: the total width of a redaction bar encodes
 * the sum of advance widths of the redacted characters at the active font size.
 */
export async function enumerateCandidates(options: NaccacheWhelanOptions): Promise<Candidate[]> {
	const {
		barWidth,
		metrics,
		fontSize,
		tolerance = 0.03,
		maxCandidates = 50,
	} = options;

	if (barWidth <= 0 || fontSize <= 0) return [];

	const toleranceUnits = barWidth * tolerance;
	const candidates: Candidate[] = [];

	for (const word of WORD_LIST) {
		const renderedWidth = metrics.stringWidth(word, fontSize);
		const error = Math.abs(renderedWidth - barWidth);
		if (error <= toleranceUnits) {
			candidates.push({
				text: word,
				widthError: error,
				probability: 0, // set below
			});
		}
	}

	// Also enumerate short digit strings (phone, SSN fragments, years, IDs)
	const avgCharWidth = metrics.stringWidth('0123456789', fontSize) / 10;
	if (avgCharWidth > 0) {
		const estimatedLen = Math.round(barWidth / avgCharWidth);
		for (let len = Math.max(1, estimatedLen - 2); len <= estimatedLen + 2; len++) {
			for (const digits of generateDigitCandidates(len)) {
				const renderedWidth = metrics.stringWidth(digits, fontSize);
				const error = Math.abs(renderedWidth - barWidth);
				if (error <= toleranceUnits) {
					candidates.push({ text: digits, widthError: error, probability: 0 });
				}
			}
		}
	}

	// Score and deduplicate
	const seen = new Set<string>();
	const scored: Candidate[] = [];
	for (const c of candidates) {
		if (seen.has(c.text)) continue;
		seen.add(c.text);
		const widthScore = 1 - c.widthError / (barWidth * tolerance + 1);
		const freqScore = scoreByFrequency(c.text);
		scored.push({ ...c, probability: widthScore * 0.6 + freqScore * 0.4 });
	}

	scored.sort((a, b) => b.probability - a.probability);
	return scored.slice(0, maxCandidates);
}

/** Generate a small set of representative digit strings of given length. */
function* generateDigitCandidates(len: number): Generator<string> {
	if (len <= 0) return;
	// Common year range
	if (len === 4) {
		for (let y = 1950; y <= 2030; y++) yield String(y);
		return;
	}
	// Sample numeric patterns
	if (len <= 3) {
		for (let n = 0; n < Math.min(999, 10 ** len); n++) {
			yield String(n).padStart(len, '0');
		}
	}
}
